                  />
                  <Search size={12} className="absolute left-2.5 text-content-muted" />
                  {isSupported && (
                    <button
                      type="button"
                      onMouseDown={(e) => e.preventDefault()}
                      onClick={isListening ? stopListening : startListening}
                      className={`absolute right-7 p-1 rounded transition-colors ${
                        isListening ? 'text-red-500 bg-red-50 animate-pulse' : 'text-content-muted hover:text-content hover:bg-app'
                      }`}
                      title="Dictée vocale"
                    >
                      <Mic size={12} />
                    </button>
                  )}
                  <button
                    type="button"
                    onClick={() => { setSearchOpen(false); setSearchVal(''); }}
                    className="absolute right-2 text-content-muted hover:text-content"
                  >
                    <X size={12} />
                  </button>
                </div>
              ) : (
                <button
                  onClick={() => setSearchOpen(true)}
                  className="p-2 rounded-lg text-content-muted hover:bg-surface-raised transition-colors flex items-center gap-1.5 text-xs font-medium"
                  title="Rechercher"
                >
                  <Search size={14} />
                  {isSupported && <Mic size={14} className="text-indigo-500" />}
                </button>
              )}

              {/* Desktop Dropdown Results */}
              {searchOpen && searchVal.trim() !== '' && (
                <div className="absolute top-full right-0 mt-2 bg-surface border border-border rounded-xl shadow-xl overflow-hidden w-48 z-50 py-1">
                  {PUBLIC_SECTIONS.filter(
                    (sec) =>
                      sec.label.toLowerCase().includes(searchVal.toLowerCase()) ||
                      sec.synonyms.some((syn) => syn.includes(searchVal.toLowerCase()))
                  ).map((sec) => (
                    <Link
                      key={sec.path}
                      to={sec.path}
                      onMouseDown={(e) => {
                        e.preventDefault();
                        navigate(sec.path);
                        setSearchOpen(false);
                        setSearchVal('');
                      }}
                      className="block px-4 py-2 text-xs font-medium text-content hover:bg-surface-raised transition-colors"
                    >
                      {sec.label}
                    </Link>
                  ))}
                </div>
              )}
            </div>

            {/* CTA */}
            <div className="hidden md:flex items-center gap-3">
              <ThemeToggle variant="dropdown" />
              <Link
                to="/connexion"
                className="text-sm font-medium text-content-secondary hover:text-content transition-colors"
              >
                Connexion
              </Link>
              <Link
                to="/connexion"
                className="btn-gradient text-sm px-4 py-2 rounded-full font-semibold"
              >
                Démarrer gratuitement
              </Link>
            </div>

            {/* Mobile menu button */}
            <div className="md:hidden flex items-center gap-1">
              <button
                onClick={() => setSearchOpen(o => !o)}
                className={`p-2 rounded-lg transition-colors ${
                  searchOpen ? 'text-indigo-600 bg-surface-raised' : 'text-content-muted hover:bg-surface-raised'
                }`}
                aria-label="Rechercher"
              >
                <Search size={18} />
              </button>
              <ThemeToggle />
              <button
                className="p-2 rounded-lg text-content-muted hover:bg-surface-raised transition-colors"
                onClick={() => setMenuOpen(o => !o)}
                aria-label="Menu"
              >
                {menuOpen ? <X size={20} /> : <Menu size={20} />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Search Overlay */}
        {searchOpen && (
          <div className="md:hidden border-t border-border-subtle bg-surface px-4 py-2 relative flex items-center gap-2">
            <div className="relative flex-1">
              <input
                type="text"
                value={searchVal}
                onChange={(e) => setSearchVal(e.target.value)}
                placeholder="Rechercher une section..."
                className="w-full pl-8 pr-12 py-1.5 text-xs bg-surface-raised border border-border rounded-lg text-content focus:outline-none"
                autoFocus
              />
              <Search size={12} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-content-muted" />
              {isSupported && (
                <button
                  type="button"
                  onClick={isListening ? stopListening : startListening}
                  className={`absolute right-7 top-1/2 -translate-y-1/2 p-1 rounded transition-colors ${
                    isListening ? 'text-red-500 bg-red-50 animate-pulse' : 'text-content-muted hover:text-content'
                  }`}
                >
                  <Mic size={12} />
                </button>
              )}
              <button
                type="button"
                onClick={() => { setSearchOpen(false); setSearchVal(''); }}
                className="absolute right-2 top-1/2 -translate-y-1/2 text-content-muted hover:text-content"
              >
                <X size={12} />
              </button>
            </div>
            {/* Mobile Dropdown Results */}
            {searchVal.trim() !== '' && (
              <div className="absolute top-full left-0 right-0 bg-surface border-b border-border shadow-lg z-50 py-1">
                {PUBLIC_SECTIONS.filter(
                  (sec) =>
                    sec.label.toLowerCase().includes(searchVal.toLowerCase()) ||
                    sec.synonyms.some((syn) => syn.includes(searchVal.toLowerCase()))
                ).map((sec) => (
                  <Link
                    key={sec.path}
                    to={sec.path}
                    onClick={() => {
                      navigate(sec.path);
                      setSearchOpen(false);
                      setSearchVal('');
                    }}
                    className="block px-6 py-2.5 text-xs font-medium text-content hover:bg-surface-raised transition-colors"
                  >
                    {sec.label}
                  </Link>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Mobile menu */}
        {menuOpen && (
          <div className="md:hidden border-t border-border-subtle bg-surface px-4 py-4 space-y-1">
            {NAV_LINKS.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setMenuOpen(false)}
                className="block px-3 py-2.5 rounded-xl text-sm font-medium text-content-secondary hover:bg-app hover:text-content transition-colors"
              >
                {link.label}
              </Link>
            ))}
            <div className="pt-3 flex flex-col gap-2">
              <Link
                to="/connexion"
                className="block text-center text-sm font-medium text-content-secondary border border-border rounded-xl px-4 py-2.5 hover:bg-app transition-colors"
              >
                Connexion
              </Link>
              <Link
                to="/connexion"
                className="block text-center btn-gradient text-sm px-4 py-2.5 rounded-xl font-semibold"
              >
                Démarrer gratuitement
              </Link>
            </div>
          </div>
        )}
      </header>

      {/* Page content */}
      <main className="flex-1">
        <Outlet />
      </main>

      {/* Footer */}
      <footer className="bg-slate-900 dark:bg-surface border-t border-slate-800 dark:border-border-subtle text-slate-400 py-16">
        <div className="max-w-6xl mx-auto px-6 sm:px-12 lg:px-20 xl:px-28">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-8 mb-12">
            <div className="col-span-2 md:col-span-1">
              <div className="flex items-center gap-2.5 mb-4">
                <img src="/images/logo-original.png" alt="Campus Logo" className="w-9 h-9 rounded-xl object-cover" />
                <span className="font-heading font-bold text-xl text-white">CAMPUS</span>
              </div>
              <p className="text-sm text-slate-500 leading-relaxed">
                La plateforme qui modernise la gestion universitaire.
              </p>
            </div>
            <div>
              <h5 className="text-sm font-semibold text-white mb-4">Navigation</h5>
              <ul className="space-y-2.5 text-sm">
                {NAV_LINKS.map((link) => (
                  <li key={link.path}>
                    <Link to={link.path} className="hover:text-white transition-colors">
                      {link.label}
                    </Link>
                  </li>
                ))}
              </ul>
            </div>
            <div>
              <h5 className="text-sm font-semibold text-white mb-4">Accès</h5>
              <ul className="space-y-2.5 text-sm">
                <li>
                  <Link to="/connexion" className="hover:text-white transition-colors">
                    Connexion
                  </Link>
                </li>
                <li>
                  <Link to="/connexion" className="hover:text-white transition-colors">
                    Démarrer gratuitement
                  </Link>
                </li>
              </ul>
            </div>
            <div>
              <h5 className="text-sm font-semibold text-white mb-4">Légal</h5>
              <ul className="space-y-2.5 text-sm">
                <li>
                  <Link to="/mentions-legales" className="hover:text-white transition-colors">
                    Mentions légales
                  </Link>
                </li>
                <li>
                  <Link to="/conditions" className="hover:text-white transition-colors">
                    Conditions d'utilisation
                  </Link>
                </li>
                <li>
                  <Link to="/confidentialite" className="hover:text-white transition-colors">
                    Confidentialité
                  </Link>
                </li>
              </ul>
            </div>
          </div>
          <div className="border-t border-slate-800 pt-8 flex flex-col sm:flex-row items-center justify-between gap-4">
            <p className="text-sm text-slate-600">© {new Date().getFullYear()} CAMPUS. Tous droits réservés.</p>
            <p className="text-sm text-slate-600">Conçu pour l'excellence universitaire 🎓</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { LogOut, Settings, ChevronDown, GraduationCap, Trash2, Plus, X } from 'lucide-react';
import { useAuthStore } from '../store/authStore';
import { navigationByRole, roleLabels } from '../constants/navigation';
import { Avatar } from '../components/ui/AvatarGroup';
import { useRegistrationStore } from '../store/registrationStore';
import { useRealtimeDataStore } from '../store/realtimeDataStore';
import { useChatStore } from '../store/chatStore';
import { ToastSuccess, ToastError } from '../controllers/Toast-emitter';
import { useTranslation } from '../hooks/useTranslation';
import { labelToKeyMap, sectionToKeyMap } from '../constants/translations';

interface SidebarProps {
  collapsed?: boolean;
}

export default function Sidebar({ collapsed = false }: SidebarProps) {
  const { user, logout, deleteAccount } = useAuthStore();
  const location = useLocation();
  const { t } = useTranslation();

  const [showCreateModal, setShowCreateModal] = useState(false);
  const [newUnivName, setNewUnivName] = useState('');
  const [newUnivCity, setNewUnivCity] = useState('');
  const [newUnivCountry, setNewUnivCountry] = useState('');
  const [creatingUniv, setCreatingUniv] = useState(false);
  const { addUniversity, currentUniversity } = useRealtimeDataStore();
  const switchUniversity = useAuthStore(state => state.switchUniversity);

  const handleCreateUniversity = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    if (!newUnivName.trim() || !newUnivCity.trim() || !newUnivCountry.trim()) {
      ToastError("Veuillez remplir tous les champs.");
      return;
    }
    setCreatingUniv(true);
    try {
      await addUniversity({
        name: newUnivName.trim(),
        city: newUnivCity.trim(),
        country: newUnivCountry.trim(),
        plan: 'pro',
        status: 'actif',
        studentsCount: 0,
        teachersCount: 0,
        mrr: 0,
        createdAt: new Date().toISOString().split('T')[0],
        adminUid: user.id,
        adminName: user.name,
        adminEmail: user.email
      });
      ToastSuccess("Nouvelle université créée avec succès !");
      setShowCreateModal(false);
      setNewUnivName('');
      setNewUnivCity('');
      setNewUnivCountry('');
    } catch (err: any) {
      console.error(err);
      ToastError("Erreur lors de la création de l'université.");
    } finally {
      setCreatingUniv(false);
    }
  };

  const handleDeleteAccount = async () => {
    if (window.confirm(t('nav.delete_confirm'))) {
      try {
        await deleteAccount();
        ToastSuccess(t('nav.delete_success'));
      } catch (err: any) {
        ToastError(err.message || t('nav.delete_error'));
      }
    }
  };

  const { requests, subscribe: subscribeReg, teardown: teardownReg } = useRegistrationStore();
  const { universities, transactions, grades, students, teachers } = useRealtimeDataStore();
  const { subscribeToAllUserChats, totalUnreadCount } = useChatStore();

  const adminUniversities = user && user.role === 'UNIVERSITY_ADMIN'
    ? universities.filter(u => u.adminUid === user.id || u.adminEmail === user.email || u.id === user.universityId)
    : [];

  if (user && user.role === 'UNIVERSITY_ADMIN' && user.universityId && !adminUniversities.some(u => u.id === user.universityId)) {
    adminUniversities.push({
      id: user.universityId,
      name: currentUniversity?.name || 'CAMPUS Établissement',
      city: currentUniversity?.city || '',
      country: currentUniversity?.country || '',
      plan: 'pro',
      status: 'actif',
      studentsCount: 0,
      teachersCount: 0,
      mrr: 0,
      createdAt: ''
    });
  }

  useEffect(() => {
    if (user && (user.role === 'SUPER_ADMIN' || user.role === 'UNIVERSITY_ADMIN')) {
      subscribeReg();
      return () => teardownReg();
    }
  }, [user, subscribeReg, teardownReg]);

  useEffect(() => {
    if (user && (user.role === 'STUDENT' || user.role === 'TEACHER') && user.universityId) {
      const allUsers = [
        ...students.map(s => ({
          uid: s.id,
          id: s.id,
          name: s.name,
          prenom: s.name ? s.name.split(' ')[0] : '',
          nom: s.name ? s.name.split(' ').slice(1).join(' ') : '',
          email: s.email,
          role: 'STUDENT' as const,
          status: s.status,
          universityId: s.universityId
        })),
        ...teachers.map(t => ({
          uid: t.id,
          id: t.id,
          name: t.name,
          prenom: t.name ? t.name.split(' ')[0] : '',
          nom: t.name ? t.name.split(' ').slice(1).join(' ') : '',
          email: t.email,
          role: 'TEACHER' as const,
          status: t.status,
          universityId: t.universityId
        }))
      ];
      const unsub = subscribeToAllUserChats(user.id, user.role, user.universityId, allUsers);
      return () => unsub();
    }
  }, [user, students, teachers, subscribeToAllUserChats]);

  if (!user) return null;

  const navSections = navigationByRole[user.role] ?? [];
  const roleLabel = t(`role.${user.role}`, roleLabels[user.role]);

  const isActive = (path: string) => {
    if (path === '/super-admin' || path === '/admin' || path === '/enseignant' || path === '/etudiant' || path === '/parent') {
      return location.pathname === path;
    }
    return location.pathname.startsWith(path);
  };

  return (
    <aside
      className={`h-screen flex flex-col bg-surface border-r border-border-subtle transition-all duration-300 ${
        collapsed ? 'w-16' : 'w-64'
      }`}
    >
      {/* Logo */}
      <div className={`flex items-center gap-3 px-5 py-5 border-b border-border-subtle ${collapsed ? 'justify-center px-3' : ''}`}>
        <img src="/images/logo-original.png" alt="Logo" className="w-9 h-9 rounded-xl flex-shrink-0 shadow-md object-cover" />
        {!collapsed && (
          <div>
            <span className="font-heading font-bold text-content text-lg leading-none">CAMPUS</span>
            <p className="text-xs text-content-muted mt-0.5">{roleLabel}</p>
          </div>
        )}
      </div>

      {/* Selector and + Button */}
      {user.role === 'UNIVERSITY_ADMIN' && !collapsed && (
        <div className="px-4 py-2.5 border-b border-border-subtle flex items-center justify-between gap-2 bg-surface-raised/30">
          <div className="flex-1 min-w-0">
            <label className="block text-[9px] font-bold text-content-muted uppercase tracking-wider mb-1">Établissement Actif</label>
            <select
              value={user.universityId || ''}
              onChange={(e) => {
                if (e.target.value) {
                  switchUniversity(e.target.value);
                  ToastSuccess("Établissement actif modifié !");
                }
              }}
              className="select select-bordered select-xs w-full text-xs font-semibold bg-surface border-border-subtle focus:outline-none focus:border-indigo-500 h-8 rounded-lg"
            >
              {adminUniversities.map((u) => (
                <option key={u.id} value={u.id}>
                  🏫 {u.name}
                </option>
              ))}
            </select>
          </div>
          <button
            onClick={() => setShowCreateModal(true)}
            className="btn btn-square btn-xs btn-outline border-border-subtle text-indigo-600 dark:text-indigo-400 hover:bg-indigo-600 hover:text-white dark:hover:bg-indigo-600 dark:hover:text-white rounded-lg flex items-center justify-center p-1 cursor-pointer self-end h-8 w-8"
            title="Créer un autre établissement"
          >
            <Plus size={16} />
          </button>
        </div>
      )}

      {/* Navigation */}
      <nav className="flex-1 overflow-y-auto py-4 px-3 space-y-6">
        {navSections.map((section, si) => (
          <div key={si}>
            {section.title && !collapsed && (
              <p className="text-[10px] font-bold text-content-muted uppercase tracking-widest px-2 mb-2">
                {t(sectionToKeyMap[section.title] || section.title)}
              </p>
            )}
            <ul className="space-y-1">
              {section.items.map((item) => {
                const active = isActive(item.path);
                const Icon = item.icon;

                let badgeValue: string | undefined = undefined;

                if (user.role === 'SUPER_ADMIN') {
                  if (item.path === '/app/super-admin/demandes') {
                    const count = requests.filter(r => r.role === 'UNIVERSITY_ADMIN' && r.status === 'pending').length;
                    if (count > 0) badgeValue = `(${count})`;
                  } else if (item.path === '/app/super-admin/universites') {
                    const count = universities.filter(u => u.status === 'en_attente').length;
                    if (count > 0) badgeValue = `(${count})`;
                  }
                } else if (user.role === 'UNIVERSITY_ADMIN') {
                  if (item.path === '/app/admin/demandes') {
                    const count = requests.filter(r => r.universityId === user.universityId && r.status === 'pending').length;
                    if (count > 0) badgeValue = `(${count})`;
                  } else if (item.path === '/app/admin/finance') {
                    const count = transactions.filter(t => t.status === 'en_attente').length;
                    if (count > 0) badgeValue = `(${count})`;
                  }
                } else if (user.role === 'STUDENT') {
                  if (item.path === '/app/etudiant/paiements') {
                    // Count unpaid/late transactions
                    const count = transactions.filter(t => t.status === 'en_retard' || t.status === 'en_attente').length;
                    if (count > 0) badgeValue = `(${count})`;
                  }
                } else if (user.role === 'PARENT') {
                  if (item.path === '/app/parent/suivi') {
                    const count = transactions.filter(t => t.status === 'en_retard' || t.status === 'en_attente').length;
                    if (count > 0) badgeValue = `(${count})`;
                  }
                }

                if (item.path === '/app/messagerie') {
                  if (totalUnreadCount > 0) {
                    badgeValue = `(${totalUnreadCount})`;
                  }
                }

                return (
                  <li key={item.path}>
                    <Link
                      to={item.path}
                      title={collapsed ? t(labelToKeyMap[item.label] || item.label) : undefined}
                      className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all duration-150 group ${
                        active
                          ? 'bg-indigo-50 text-indigo-600 dark:text-indigo-400 shadow-sm'
                          : 'text-content-secondary hover:bg-surface-raised hover:text-content'
                      } ${collapsed ? 'justify-center' : ''}`}
                    >
                      <div className="relative flex items-center justify-center flex-shrink-0">
                        <Icon
                          size={18}
                          className={`flex-shrink-0 transition-colors ${
                            active ? 'text-indigo-500 dark:text-indigo-400' : 'text-content-muted group-hover:text-content-secondary'
                          }`}
                        />
                        {badgeValue && collapsed && (
                          <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 border border-white rounded-full animate-pulse z-10" />
                        )}
                      </div>
                      {!collapsed && (
                        <span className="flex-1">{t(labelToKeyMap[item.label] || item.label)}</span>
                      )}
                      {!collapsed && badgeValue && (
                        <span className="text-xs font-bold text-red-500 animate-pulse ml-auto">
                          {badgeValue}
                        </span>
                      )}
                      {active && !collapsed && !badgeValue && (
                        <span className="w-1.5 h-1.5 rounded-full bg-indigo-500 flex-shrink-0 ml-auto" />
                      )}
                    </Link>
                  </li>
                );
              })}
            </ul>
          </div>
        ))}
      </nav>

      {/* Footer user */}
      <div className={`border-t border-border-subtle p-3 ${collapsed ? '' : ''}`}>
        {!collapsed ? (
          <div className="dropdown dropdown-top w-full">
            <div
              tabIndex={0}
              role="button"
              className="flex items-center gap-3 p-2 rounded-xl hover:bg-surface-raised cursor-pointer transition-colors w-full"
            >
              <Avatar name={user.name} size="sm" />
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-content truncate">{user.name}</p>
                <p className="text-xs text-content-muted truncate">{user.email}</p>
              </div>
              <ChevronDown size={14} className="text-content-muted flex-shrink-0" />
            </div>
            <ul
              tabIndex={0}
              className="dropdown-content menu menu-sm bg-surface rounded-xl shadow-xl border border-border w-52 mb-2 z-50 p-2"
            >
              <li>
                <Link to="/app/parametres" className="flex items-center gap-2 text-content-secondary font-medium">
                  <Settings size={14} /> {t('nav.settings')}
                </Link>
              </li>
              <li>
                <button
                  onClick={handleDeleteAccount}
                  className="flex items-center gap-2 text-red-600 hover:bg-red-50 hover:text-red-700 dark:hover:bg-red-950/40 w-full text-left font-medium"
                >
                  <Trash2 size={14} /> {t('nav.delete_account')}
                </button>
              </li>
              <li>
                <button
                  onClick={logout}
                  className="flex items-center gap-2 text-red-500 hover:bg-red-50 w-full text-left font-medium"
                >
                  <LogOut size={14} /> {t('nav.logout')}
                </button>
              </li>
            </ul>
          </div>
        ) : (
          <button
            onClick={logout}
            className="w-full flex justify-center p-2 rounded-xl hover:bg-red-50 text-content-muted hover:text-red-500 transition-colors"
            title={t('nav.logout')}
          >
            <LogOut size={18} />
          </button>
        )}
      </div>

      {/* Modale de création d'université */}
      {showCreateModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm px-4">
          <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 max-w-md w-full border border-slate-100 dark:border-slate-800 shadow-2xl relative animate-fade-up">
            <button
              onClick={() => setShowCreateModal(false)}
              className="absolute right-4 top-4 p-1 rounded-lg text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800"
            >
              <X size={16} />
            </button>

            <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-2 flex items-center gap-2">
              <Plus className="text-indigo-500" size={20} />
              Créer un nouvel Établissement
            </h3>
            <p className="text-xs text-slate-500 dark:text-slate-400 mb-4">
              Ajoutez un autre établissement à votre gestion multi-tenant.
            </p>

            <form onSubmit={handleCreateUniversity} className="space-y-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Nom de l'établissement</label>
                <input
                  type="text"
                  placeholder="Ex: Université Félix Houphouët-Boigny"
                  value={newUnivName}
                  onChange={(e) => setNewUnivName(e.target.value)}
                  required
                  className="input input-bordered input-sm w-full bg-slate-50 dark:bg-slate-950 border-slate-200 dark:border-slate-800 text-sm h-10 rounded-xl"
                />
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-1">
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Ville</label>
                  <input
                    type="text"
                    placeholder="Ex: Abidjan"
                    value={newUnivCity}
                    onChange={(e) => setNewUnivCity(e.target.value)}
                    required
                    className="input input-bordered input-sm w-full bg-slate-50 dark:bg-slate-950 border-slate-200 dark:border-slate-800 text-sm h-10 rounded-xl"
                  />
                </div>
                <div className="space-y-1">
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Pays</label>
                  <input
                    type="text"
                    placeholder="Ex: Côte d'Ivoire"
                    value={newUnivCountry}
                    onChange={(e) => setNewUnivCountry(e.target.value)}
                    required
                    className="input input-bordered input-sm w-full bg-slate-50 dark:bg-slate-950 border-slate-200 dark:border-slate-800 text-sm h-10 rounded-xl"
                  />
                </div>
              </div>

              <div className="flex gap-2 justify-end mt-6">
                <button
                  type="button"
                  onClick={() => setShowCreateModal(false)}
                  className="btn btn-sm btn-ghost rounded-xl"
                >
                  Annuler
                </button>
                <button
                  type="submit"
                  disabled={creatingUniv}
                  className="btn btn-sm btn-primary rounded-xl px-4"
                >
                  {creatingUniv ? <span className="loading loading-spinner loading-xs" /> : 'Créer'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </aside>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Bell, Menu, Search, X, BookOpen, Users, FileText, Trash2, Mic } from 'lucide-react';
import { useAuthStore } from '../store/authStore';
import { Avatar } from '../components/ui/AvatarGroup';
import ThemeToggle from '../components/shared/ThemeToggle';
import { useNotificationStore } from '../store/notificationStore';
import { useRealtimeDataStore } from '../store/realtimeDataStore';
import { useNavigate } from 'react-router-dom';
import { navigationByRole } from '../constants/navigation';
import { useTranslation } from '../hooks/useTranslation';
import { useSpeechToText } from '../hooks/useSpeechToText';

interface TopbarProps {
  onToggleSidebar: () => void;
  sidebarCollapsed: boolean;
}

export default function Topbar({ onToggleSidebar, sidebarCollapsed }: TopbarProps) {
  const { user } = useAuthStore();
  const navigate = useNavigate();
  const { t, language } = useTranslation();
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchVal, setSearchVal] = useState('');
  const searchInputRef = useRef<HTMLInputElement>(null);
  const [time, setTime] = useState(new Date());
  const [selectedNotif, setSelectedNotif] = useState<any | null>(null);

  const { isListening, isSupported, startListening, stopListening } = useSpeechToText({
    onResult: (text) => {
      setSearchVal(text);
      if (searchInputRef.current) {
        searchInputRef.current.focus();
      }
    },
  });

  const { notifications, markAsRead, markAllAsRead, removeNotification, removeAllNotifications } = useNotificationStore();
  const { students, teachers, courses } = useRealtimeDataStore();
  const unreadCount = notifications.filter(n => !n.read).length;

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
        e.preventDefault();
        setSearchOpen(true);
      } else if (e.key === 'Escape' && searchOpen) {
        setSearchOpen(false);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [searchOpen]);

  const formattedDate = time.toLocaleDateString(language === 'en' ? 'en-US' : 'fr-FR', {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  });
  const formattedTime = time.toLocaleTimeString(language === 'en' ? 'en-US' : 'fr-FR', {
    hour: '2-digit', minute: '2-digit', second: '2-digit',
  });

  if (!user) return null;

  // --- OMNISEARCH LOGIC ---
  const searchResults = (() => {
    if (!searchVal.trim()) return null;
    const term = searchVal.toLowerCase();
    const results: any[] = [];

    // 1. Pages/Sections
    const navSections = navigationByRole[user.role] || [];
    navSections.forEach(section => {
      section.items.forEach(item => {
        if (item.label.toLowerCase().includes(term)) {
          results.push({ type: 'Page', label: item.label, path: item.path, icon: item.icon });
        }
      });
    });

    // 2. Étudiants
    students.forEach(s => {
      if (s.name.toLowerCase().includes(term) || s.email.toLowerCase().includes(term) || (s.studentId && s.studentId.toLowerCase().includes(term))) {
        results.push({ type: 'Étudiant', label: `${s.name} (${s.studentId || s.email})`, data: s });
      }
    });

    // 3. Professeurs
    teachers.forEach(t => {
      if (t.name.toLowerCase().includes(term) || t.email.toLowerCase().includes(term)) {
        results.push({ type: 'Professeur', label: `${t.name} (${t.specialite || t.email})`, data: t });
      }
    });

    // 4. Cours
    courses.forEach(c => {
      if (c.title.toLowerCase().includes(term) || c.code.toLowerCase().includes(term)) {
        results.push({ type: 'Cours', label: `${c.title} [${c.code}]`, data: c });
      }
    });

    return results.slice(0, 8);
  })();

  const handleResultClick = (res: any) => {
    setSearchOpen(false);
    setSearchVal('');
    if (res.type === 'Page') {
      navigate(res.path);
    } else if (res.type === 'Étudiant') {
      const path = user.role === 'TEACHER' ? '/app/enseignant/etudiants' : '/app/admin/etudiants';
      navigate(path, { state: { search: res.data.name } });
    } else if (res.type === 'Professeur') {
      navigate('/app/admin/enseignants', { state: { search: res.data.name } });
    } else if (res.type === 'Cours') {
      const path = user.role === 'STUDENT' ? '/app/etudiant/cours' : user.role === 'TEACHER' ? '/app/enseignant/cours' : '/app/admin/cours';
      navigate(path, { state: { search: res.data.code } });
    }
  };

  return (
    <header className="h-16 bg-surface/80 backdrop-blur-md border-b border-border-subtle flex items-center px-4 gap-3 sticky top-0 z-40 transition-colors duration-200">
      <button
        onClick={onToggleSidebar}
        className="p-2 rounded-xl hover:bg-surface-raised text-content-muted hover:text-content transition-colors"
        aria-label={sidebarCollapsed ? (language === 'en' ? 'Open menu' : 'Ouvrir menu') : (language === 'en' ? 'Collapse menu' : 'Réduire menu')}
      >
        <Menu size={18} />
      </button>

      {/* OmniSearch bar */}
      <div className={`flex-1 max-w-xl transition-all duration-200 relative ${searchOpen ? 'opacity-100' : 'opacity-100'}`}>
        {searchOpen ? (
          <div>
            <Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-content-muted" />
            <input
              ref={searchInputRef}
              autoFocus
              type="text"
              value={searchVal}
              onChange={e => setSearchVal(e.target.value)}
              placeholder={t('topbar.search_placeholder')}
              className="w-full pl-9 pr-16 py-2 text-sm bg-app border border-border rounded-xl text-content focus:outline-none focus:border-indigo-400 focus:ring-2 focus:ring-indigo-500/20 transition-all shadow-sm"
              onBlur={() => setTimeout(() => setSearchOpen(false), 200)}
            />
            {isSupported && (
              <button
                type="button"
                onMouseDown={(e) => e.preventDefault()}
                onClick={isListening ? stopListening : startListening}
                className={`absolute right-8 top-1/2 -translate-y-1/2 p-1 rounded-lg transition-colors ${
                  isListening
                    ? 'text-red-500 bg-red-50 dark:bg-red-950/30 animate-pulse'
                    : 'text-content-muted hover:text-content hover:bg-surface-raised'
                }`}
                title={isListening ? "Arrêter la dictée" : "Recherche vocale"}
              >
                <Mic size={14} />
              </button>
            )}
            <button onClick={() => { setSearchOpen(false); setSearchVal(''); }} className="absolute right-3 top-1/2 -translate-y-1/2 text-content-muted hover:text-content">
              <X size={14} />
            </button>

            {/* OmniSearch Dropdown */}
            {searchResults && searchResults.length > 0 && (
              <div className="absolute top-full left-0 right-0 mt-2 bg-surface border border-border rounded-xl shadow-xl overflow-hidden z-50">
                <div className="max-h-[300px] overflow-y-auto py-2">
                  {searchResults.map((res, idx) => (
                    <div 
                      key={idx} 
                      onMouseDown={(e) => { e.preventDefault(); handleResultClick(res); }}
                      className="px-4 py-2 hover:bg-surface-raised cursor-pointer flex items-center gap-3 transition-colors"
                    >
                      <div className="flex-shrink-0 w-8 h-8 rounded-lg bg-indigo-50 dark:bg-indigo-900/30 flex items-center justify-center text-indigo-600 dark:text-indigo-400">
                        {res.type === 'Page' ? (res.icon ? <res.icon size={16} /> : <FileText size={16} />) : 
                         res.type === 'Étudiant' ? <Users size={16} /> :
                         res.type === 'Professeur' ? <Users size={16} /> :
                         <BookOpen size={16} />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-content truncate">{res.label}</p>
                        <p className="text-xs text-content-muted">{res.type}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
            {searchResults && searchResults.length === 0 && (
              <div className="absolute top-full left-0 right-0 mt-2 bg-surface border border-border rounded-xl shadow-xl overflow-hidden z-50 p-4 text-center">
                <p className="text-sm text-content-muted">{t('topbar.no_results')} "{searchVal}"</p>
              </div>
            )}
          </div>
        ) : (
          <button
            onClick={() => setSearchOpen(true)}
            className="flex items-center gap-2 text-sm text-content-muted bg-app border border-border rounded-xl px-3 py-2 hover:border-border transition-colors w-full sm:max-w-xs"
          >
            <Search size={14} />
            <span>{t('topbar.search_trigger')}</span>
            <span className="ml-auto text-[10px] font-mono bg-surface-muted px-1.5 py-0.5 rounded border border-border-subtle">Ctrl+K</span>
          </button>
        )}
      </div>

      {/* Real-time Date and Time */}
      <div className="hidden md:flex items-center gap-2 text-xs text-content-secondary bg-app border border-border-subtle rounded-xl px-3 py-2 font-medium">
        <span className="capitalize">{formattedDate}</span>
        <span className="text-content-muted">|</span>
        <span className="text-indigo-500 dark:text-indigo-400 font-bold font-mono">{formattedTime}</span>
      </div>

      <div className="flex-grow" />

      <ThemeToggle />

      {/* Notifications */}
      <div className="dropdown dropdown-end">
        <button
          tabIndex={0}
          className="relative p-2 rounded-xl hover:bg-surface-raised text-content-muted hover:text-content transition-colors"
          aria-label={t('topbar.notifications')}
        >
          <Bell size={18} />
          {unreadCount > 0 && (
            <span className="absolute -top-0.5 -right-0.5 w-4 h-4 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center">
              {unreadCount}
            </span>
          )}
        </button>
        <div
          tabIndex={0}
          className="dropdown-content bg-surface rounded-2xl shadow-xl border border-border w-80 mt-2 z-50 overflow-hidden"
        >
          <div className="px-4 py-3 border-b border-border-subtle flex items-center justify-between">
            <h4 className="text-sm font-semibold text-content">{t('topbar.notifications')}</h4>
            {unreadCount > 0 && (
              <span className="text-xs text-indigo-600 font-medium">{unreadCount} {t('topbar.unread')}</span>
            )}
          </div>
          <div className="divide-y divide-slate-50 dark:divide-slate-800 max-h-64 overflow-y-auto">
            {notifications.length === 0 ? (
              <div className="p-6 text-center text-xs text-content-muted">
                {t('topbar.no_notif')}
              </div>
            ) : (
              notifications.map((notif) => {
                const dateStr = notif.createdAt ? new Date(notif.createdAt).toLocaleTimeString(language === 'en' ? 'en-US' : 'fr-FR', {
                  hour: '2-digit',
                  minute: '2-digit'
                }) : '—';

                return (
                  <div
                    key={notif.id}
                    className={`flex items-start gap-3 px-4 py-3 hover:bg-surface-raised transition-colors cursor-pointer group/notif ${
                      !notif.read ? 'bg-indigo-50/30' : ''
                    }`}
                    onClick={() => {
                      markAsRead(notif.id);
                      if (notif.metadata) {
                        setSelectedNotif(notif);
                      }
                    }}
                  >
                    <div className={`w-2 h-2 rounded-full mt-1.5 flex-shrink-0 ${
                      notif.read
                        ? 'bg-surface-muted'
                        : notif.type === 'error' ? 'bg-red-500'
                        : notif.type === 'warning' ? 'bg-amber-500'
                        : notif.type === 'success' ? 'bg-emerald-500'
                        : 'bg-indigo-500'
                    }`} />
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium text-content truncate">{notif.title}</p>
                      <p className="text-xs text-content-secondary mt-0.5 truncate">{notif.message}</p>
                      <p className="text-xs text-content-muted mt-1">{dateStr}</p>
                    </div>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        removeNotification(notif.id);
                      }}
                      className="p-1 rounded-md text-content-muted hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-950/30 opacity-0 group-hover/notif:opacity-100 transition-opacity"
                      title={t('topbar.delete')}
                    >
                      <X size={12} />
                    </button>
                  </div>
                );
              })
            )}
          </div>
          <div className="px-4 py-3 border-t border-border-subtle flex gap-2 justify-between">
            <button
              onClick={markAllAsRead}
              className="text-xs text-indigo-500 hover:text-indigo-400 font-medium"
            >
              {t('topbar.mark_all_read')}
            </button>
            {notifications.length > 0 && (
              <button
                onClick={removeAllNotifications}
                className="text-xs text-red-500 hover:text-red-400 font-medium"
              >
                {t('topbar.clear_all')}
              </button>
            )}
          </div>
        </div>
      </div>

      {/* User avatar */}
      <div className="flex items-center gap-2.5 pl-2">
        <Avatar name={user.name} size="sm" />
        <div className="hidden sm:block">
          <p className="text-sm font-semibold text-content leading-none">{user.name.split(' ')[0]}</p>
        </div>
      </div>
      {/* Notification Detail Modal */}
      {selectedNotif && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm px-4 py-6">
          <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 md:p-8 max-w-lg w-full max-h-[90vh] overflow-y-auto border border-slate-100 dark:border-slate-800 shadow-2xl relative animate-fade-up text-slate-850 dark:text-slate-150">
            <button
              onClick={() => setSelectedNotif(null)}
              className="absolute right-4 top-4 p-1.5 text-slate-400 hover:text-slate-600 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-xl"
            >
              <X size={18} />
            </button>

            <div className="flex items-center gap-3 mb-6 border-b border-slate-100 dark:border-slate-800 pb-4">
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-white ${
                selectedNotif.metadata.type === 'evaluation' ? 'bg-amber-500' : 'bg-indigo-500'
              }`}>
                {selectedNotif.metadata.type === 'evaluation' ? '⭐' : '💡'}
              </div>
              <div>
                <h3 className="font-bold text-lg text-slate-900 dark:text-slate-100">{selectedNotif.title}</h3>
                <p className="text-xs text-slate-400">
                  Reçu le {new Date(selectedNotif.metadata.submittedAt || selectedNotif.createdAt).toLocaleString('fr-FR')}
                </p>
              </div>
            </div>

            <div className="space-y-4">
              {/* Contrib Info */}
              <div className="bg-slate-50 dark:bg-slate-800/40 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2">Auteur</span>
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-700 flex items-center justify-center font-bold text-xs">
                    {selectedNotif.metadata.userName.charAt(0)}
                  </div>
                  <div>
                    <p className="text-sm font-bold text-slate-800 dark:text-slate-200">{selectedNotif.metadata.userName}</p>
                    <p className="text-[10px] text-indigo-650 bg-indigo-50 dark:bg-indigo-950/40 dark:text-indigo-400 px-2 py-0.5 rounded-full inline-block font-semibold mt-0.5">
                      {selectedNotif.metadata.userRole === 'PARENT' ? 'Parent d\'élève' : 'Étudiant'}
                    </p>
                  </div>
                </div>
              </div>

              {/* Evaluation Details */}
              {selectedNotif.metadata.type === 'evaluation' && (
                <div className="space-y-4">
                  <div className="bg-indigo-50 dark:bg-indigo-950/20 border border-indigo-150 p-4 rounded-2xl flex items-center justify-between">
                    <span className="text-sm font-semibold text-slate-700 dark:text-slate-350">Note Moyenne attribuée :</span>
                    <span className="text-lg font-black text-indigo-700 dark:text-indigo-400 font-mono">{selectedNotif.metadata.average} / 5</span>
                  </div>

                  {selectedNotif.metadata.ratings && (
                    <div className="space-y-2.5">
                      <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider">Détail des critères</span>
                      <div className="grid grid-cols-2 gap-2 text-xs">
                        {[
                          { key: 'enseignement', label: "Enseignement" },
                          { key: 'infrastructures', label: "Infrastructures" },
                          { key: 'administration', label: "Administration" },
                          { key: 'services', label: "Services" }
                        ].map(c => {
                          const rating = selectedNotif.metadata.ratings[c.key] || 0;
                          return (
                            <div key={c.key} className="flex items-center justify-between bg-slate-50/50 dark:bg-slate-800/20 p-2.5 border border-slate-100/60 dark:border-slate-800 rounded-xl">
                              <span className="text-slate-550 dark:text-slate-400 font-medium truncate">{c.label}</span>
                              <span className="font-bold text-amber-500 flex items-center gap-0.5 ml-1">
                                {rating} ★
                              </span>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  )}

                  <div>
                    <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Avis / Commentaire</span>
                    <p className="text-sm text-slate-700 dark:text-slate-300 italic bg-slate-50 dark:bg-slate-800/40 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 leading-relaxed">
                      &ldquo;{selectedNotif.metadata.comment}&rdquo;
                    </p>
                  </div>
                </div>
              )}

              {/* Suggestion Details */}
              {selectedNotif.metadata.type === 'suggestion' && (
                <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Thématique</span>
                      <span className="inline-block text-xs font-semibold bg-indigo-50 dark:bg-indigo-950/40 text-indigo-650 dark:text-indigo-400 px-3 py-1.5 rounded-xl">
                        {selectedNotif.metadata.category}
                      </span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Objet</span>
                      <span className="block text-sm font-bold text-slate-800 dark:text-slate-200 mt-1">{selectedNotif.metadata.subject}</span>
                    </div>
                  </div>

                  <div>
                    <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Détails de la suggestion</span>
                    <p className="text-sm text-slate-700 dark:text-slate-300 bg-slate-50 dark:bg-slate-800/40 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 leading-relaxed whitespace-pre-line">
                      {selectedNotif.metadata.content}
                    </p>
                  </div>
                </div>
              )}
            </div>

            <div className="mt-6 flex justify-end">
              <button
                onClick={() => setSelectedNotif(null)}
                className="px-5 py-2.5 bg-slate-900 hover:bg-slate-800 text-white rounded-xl text-xs font-bold transition-colors"
              >
                Fermer
              </button>
            </div>
          </div>
        </div>
      )}
    </header>
  );
}

