              <select
                value={selectedCourse}
                onChange={e => setSelectedCourse(e.target.value)}
                className="input-premium flex-1 md:w-64 px-3 py-2 text-sm"
              >
                {myCourses.map(c => (
                  <option key={c.id} value={c.id}>{c.code} — {c.title} (S{c.semester || 1})</option>
                ))}
              </select>
