  updateUserProfile: async (data) => {
    const fbUser = auth.currentUser;
    if (!fbUser) throw new Error("Aucun utilisateur connecté.");

    set({ loading: true });
    try {
      const token = await fbUser.getIdToken();
      const dbUrl = import.meta.env.VITE_databaseURL;

      // Update password if requested
      if (data.newPassword) {
        if (data.currentPassword) {
          if (!fbUser.email) throw new Error("Email manquant.");
          const credential = EmailAuthProvider.credential(fbUser.email, data.currentPassword);
          await reauthenticateWithCredential(fbUser, credential);
        }
        await updatePassword(fbUser, data.newPassword);
      }

      // Update name if requested
      if (data.name && data.name !== fbUser.displayName) {
        await updateProfile(fbUser, { displayName: data.name });

        // We also need to update the realtime database depending on the structure
        // Since we store 'nom' and 'prenom', we might just split the name for simplicity
        const parts = data.name.split(' ');
        const prenom = parts[0];
        const nom = parts.slice(1).join(' ') || prenom;

        await axios.patch(`${dbUrl}/utilisateurs/${fbUser.uid}.json?auth=${token}`, {
          prenom,
          nom
        });

        // Also update in the specific role table
        const { user } = useAuthStore.getState();
        if (user && user.universityId) {
          if (user.role === 'STUDENT') {
            await axios.patch(`${dbUrl}/universites/${user.universityId}/etudiants/${fbUser.uid}.json?auth=${token}`, {
              name: data.name
            });
          } else if (user.role === 'TEACHER') {
            await axios.patch(`${dbUrl}/universites/${user.universityId}/enseignants/${fbUser.uid}.json?auth=${token}`, {
              name: data.name
            });
          }
        }
      }

      // Refresh the local state
      await useAuthStore.getState().refreshUserProfile();

      // Update theme if requested
      if (data.theme) {
        applyTheme(data.theme as any);
        localStorage.setItem('campus-theme', data.theme);
      }

      set({ loading: false });
    } catch (err: any) {
      set({ loading: false });
      if (err.code === 'auth/invalid-credential') {
        throw new Error("Le mot de passe actuel est incorrect.");
      }
      throw err;
    }
  },

  deleteAccount: async () => {
    const fbUser = auth.currentUser;
    if (!fbUser) throw new Error("Aucun utilisateur connecté.");

    set({ loading: true });
    try {
      const token = await fbUser.getIdToken();
      const dbUrl = import.meta.env.VITE_databaseURL;

      // 1. Get the current user profile from database to know their role and university
      const response = await axios.get(`${dbUrl}/utilisateurs/${fbUser.uid}.json?auth=${token}`);
      const userData = response.data;

      if (userData) {
        const role = userData.role;
        const universityId = userData.universityId;

        // 2. Delete the record in the university's lists depending on the role
        if (universityId) {
          if (role === 'STUDENT') {
            await axios.delete(`${dbUrl}/universites/${universityId}/etudiants/${fbUser.uid}.json?auth=${token}`);
          } else if (role === 'TEACHER') {
            await axios.delete(`${dbUrl}/universites/${universityId}/enseignants/${fbUser.uid}.json?auth=${token}`);
          } else if (role === 'UNIVERSITY_ADMIN') {
            // Remove the admin from university metadata
            await axios.patch(`${dbUrl}/universites/${universityId}.json?auth=${token}`, {
              adminUid: null,
              adminName: null,
              adminEmail: null,
            });
          }
        }
      }

      // 3. Delete the profile record in /utilisateurs
      await axios.delete(`${dbUrl}/utilisateurs/${fbUser.uid}.json?auth=${token}`);

      // 4. Delete the Firebase Auth user account
      await deleteUser(fbUser);

      // 5. Sign out
      await signOut(auth);

      set({ user: null, isAuthenticated: false, loading: false });
    } catch (err: any) {
      set({ loading: false });
      if (err.code === 'auth/requires-recent-login') {
        throw new Error("Sécurité : Veuillez vous déconnecter et vous reconnecter, puis réessayer la suppression.");
      }
      throw err;
    }
  },

  sendPasswordReset: async (email) => {
    set({ loading: true });
    try {
      await sendPasswordResetEmail(auth, email);
      set({ loading: false });
    } catch (err) {
      set({ loading: false });
      throw err;
    }
  },
}));

// Écouteur global pour gérer la session et empêcher la connexion multi-comptes
onAuthStateChanged(auth, async (fbUser) => {
  const state = useAuthStore.getState();
  if (fbUser) {
    if (!state.user || state.user.id !== fbUser.uid) {
      useAuthStore.setState({ loading: true });
      try {
        const token = await fbUser.getIdToken();
        const dbUrl = import.meta.env.VITE_databaseURL;
        const response = await axios.get(`${dbUrl}/utilisateurs/${fbUser.uid}.json?auth=${token}`);
        const userData = response.data;
        if (userData) {
          const prenom = userData.prenom || '';
          const nom = userData.nom || fbUser.displayName || 'Utilisateur';
          const fullName = prenom ? `${prenom} ${nom}`.trim() : nom;

          const { role: resolvedRole, delegation: resolvedDelegation } = await resolveUserRoleAndDelegation(userData, fbUser, dbUrl, token);

          useAuthStore.setState({
            user: {
              id: fbUser.uid,
              name: fullName,
              prenom: prenom || undefined,
              email: fbUser.email || '',
              role: resolvedRole,
              universityId: userData.universityId || 'univ-ufhb',
              status: normalizeUserStatus(userData.status as string | undefined),
              telephone: userData.telephone,
              adresse: userData.adresse,
              createdDate: userData.createdDate,
              filiere: userData.filiere,
              annee: userData.annee,
              specialite: userData.specialite,
              mustChangePassword: userData.mustChangePassword || false,
              tempPassword: userData.tempPassword || undefined,
              delegation: resolvedDelegation,
              mfaEnabled: userData.mfaEnabled || false,
            },
            isAuthenticated: true,
            loading: false
          });
        } else {
          useAuthStore.setState({ loading: false });
        }
      } catch (err) {
        console.error("Erreur lors de la synchronisation de session:", err);
        useAuthStore.setState({ loading: false });
      }
    }
  } else {
    const isDemo = state.user?.id.startsWith('usr-') || state.user?.id === 't1' || state.user?.id === 's1';
    if (state.isAuthenticated && !isDemo) {
      useAuthStore.setState({
        user: null,
        isAuthenticated: false,
        loading: false
      });
    } else {
      if (state.loading) {
        useAuthStore.setState({ loading: false });
      }
    }
  }
});

import { create } from 'zustand';
import { db } from '../../firebase-config';
import { ref, onValue, push, set, update, off } from 'firebase/database';

export interface ChatMessage {
  id: string;
  senderId: string;
  senderName: string;
  text: string;
  timestamp: string;
  read: boolean;
  isAudio?: boolean;
  audioDuration?: string;
  edited?: boolean;
  deletedFor?: Record<string, boolean>; // userId -> true
  deletedForEveryone?: boolean;
  reactions?: Record<string, string>; // userId -> emoji
  replyTo?: {
    messageId: string;
    senderName: string;
    text: string;
    isAudio?: boolean;
  };
}

export interface ChatConversation {
  chatId: string;
  recipientId: string;
  recipientName: string;
  recipientRole: 'STUDENT' | 'TEACHER';
  messages: ChatMessage[];
  lastMessage?: ChatMessage;
  unreadCount: number;
}

interface ChatState {
  conversations: ChatConversation[];
  activeChatId: string | null;
  activeMessages: ChatMessage[];
  loading: boolean;
  totalUnreadCount: number;

  sendMessage: (chatId: string, senderId: string, senderName: string, text: string, replyTo?: any) => Promise<void>;
  sendAudioMessage: (chatId: string, senderId: string, senderName: string, audioData: string, duration: string) => Promise<void>;
  editMessage: (chatId: string, messageId: string, newText: string) => Promise<void>;
  deleteMessage: (chatId: string, messageId: string, forEveryone: boolean, userId: string) => Promise<void>;
  addReaction: (chatId: string, messageId: string, userId: string, emoji: string) => Promise<void>;
  deleteConversations: (chatIds: string[], userId: string) => Promise<void>;
  subscribeToChat: (chatId: string) => () => void;
  subscribeToAllUserChats: (userId: string, userRole: 'STUDENT' | 'TEACHER', universityId: string, allUsers: any[]) => () => void;
  markChatAsRead: (chatId: string, userId: string) => Promise<void>;
  setActiveChat: (chatId: string | null) => void;
}

export const useChatStore = create<ChatState>((setStore, getStore) => ({
  conversations: [],
  activeChatId: null,
  activeMessages: [],
  loading: false,
  totalUnreadCount: 0,

  setActiveChat: (chatId) => {
    setStore({ activeChatId: chatId });
  },

  sendMessage: async (chatId, senderId, senderName, text, replyTo) => {
    if (!text.trim()) return;
    const msgRef = push(ref(db, `chats/${chatId}/messages`));
    const msgId = msgRef.key;
    if (!msgId) return;

    const msgData: any = {
      id: msgId,
      senderId,
      senderName,
      text: text.trim(),
      timestamp: new Date().toISOString(),
      read: false
    };

    if (replyTo) {
      msgData.replyTo = replyTo;
    }

    await set(msgRef, msgData);
  },

  sendAudioMessage: async (chatId, senderId, senderName, audioData, duration) => {
    const msgRef = push(ref(db, `chats/${chatId}/messages`));
    const msgId = msgRef.key;
    if (!msgId) return;

    await set(msgRef, {
      id: msgId,
      senderId,
      senderName,
      text: audioData,
      timestamp: new Date().toISOString(),
      read: false,
      isAudio: true,
      audioDuration: duration
    });
  },

  editMessage: async (chatId, messageId, newText) => {
    if (!newText.trim()) return;
    const msgRef = ref(db, `chats/${chatId}/messages/${messageId}`);
    await update(msgRef, {
      text: newText.trim(),
      edited: true
    });
  },

  deleteMessage: async (chatId, messageId, forEveryone, userId) => {
    const msgRef = ref(db, `chats/${chatId}/messages/${messageId}`);
    if (forEveryone) {
      await update(msgRef, {
        text: 'Ce message a été supprimé',
        deletedForEveryone: true
      });
    } else {
      await set(ref(db, `chats/${chatId}/messages/${messageId}/deletedFor/${userId}`), true);
    }
  },

  addReaction: async (chatId, messageId, userId, emoji) => {
    const reactionRef = ref(db, `chats/${chatId}/messages/${messageId}/reactions/${userId}`);
    await set(reactionRef, emoji);
  },

  deleteConversations: async (chatIds, userId) => {
    const updates: Record<string, any> = {};
    const conversations = getStore().conversations;

    chatIds.forEach(chatId => {
      const conv = conversations.find(c => c.chatId === chatId);
      if (conv) {
        conv.messages.forEach(msg => {
          updates[`chats/${chatId}/messages/${msg.id}/deletedFor/${userId}`] = true;
        });
      }
    });

    if (Object.keys(updates).length > 0) {
      await update(ref(db), updates);
    }
  },

  subscribeToChat: (chatId) => {
    const messagesRef = ref(db, `chats/${chatId}/messages`);

    const unsubscribe = onValue(messagesRef, (snapshot) => {
      const data = snapshot.val();
      const list: ChatMessage[] = [];
      if (data) {
        Object.entries(data).forEach(([id, m]: [string, any]) => {
          if (m) {
            // Check if deleted for me
            const isDeletedForMe = m.deletedFor && m.deletedFor[getStore().activeChatId || ''] === true; // wait, let's use the local list filter to exclude deleted messages
            list.push({
              id,
              senderId: m.senderId,
              senderName: m.senderName,
              text: m.text,
              timestamp: m.timestamp,
              read: !!m.read,
              isAudio: !!m.isAudio,
              audioDuration: m.audioDuration,
              edited: !!m.edited,
              deletedFor: m.deletedFor || undefined,
              deletedForEveryone: !!m.deletedForEveryone,
              reactions: m.reactions || undefined,
              replyTo: m.replyTo || undefined
            });
          }
        });
      }

      // Sort by timestamp
      list.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

      setStore({ activeMessages: list });
    });

    return () => {
      off(messagesRef, 'value', unsubscribe);
    };
  },

  subscribeToAllUserChats: (userId, userRole, universityId, allUsers) => {
    const conversationMap: Record<string, ChatConversation> = {};
    const unsubscribers: (() => void)[] = [];

    const partners = allUsers.filter(u => 
      u && 
      u.universityId === universityId && 
      (u.status === 'active' || u.status === 'actif') && 
      u.uid !== userId && 
      (userRole === 'STUDENT' ? u.role === 'TEACHER' : u.role === 'STUDENT')
    );

    // Initialize all conversations in the map
    partners.forEach(partner => {
      const studentId = userRole === 'STUDENT' ? userId : partner.uid;
      const teacherId = userRole === 'STUDENT' ? partner.uid : userId;
      const chatId = `chat_${studentId}_${teacherId}`;

      conversationMap[chatId] = {
        chatId,
        recipientId: partner.uid,
        recipientName: `${partner.prenom || ''} ${partner.nom || ''}`.trim() || partner.name || partner.email,
        recipientRole: partner.role,
        messages: [],
        unreadCount: 0
      };
    });

    const updateStoreState = () => {
      let globalUnread = 0;
      const conversationList = Object.values(conversationMap);

      conversationList.forEach(c => {
        globalUnread += c.unreadCount;
      });

      conversationList.sort((a, b) => {
        if (!a.lastMessage) return 1;
        if (!b.lastMessage) return -1;
        return new Date(b.lastMessage.timestamp).getTime() - new Date(a.lastMessage.timestamp).getTime();
      });

      setStore({ 
        conversations: conversationList,
        totalUnreadCount: globalUnread
      });
    };

    // Set up a listener for each chatId
    Object.keys(conversationMap).forEach(chatId => {
      const chatMessagesRef = ref(db, `chats/${chatId}/messages`);
      const unsub = onValue(chatMessagesRef, (snapshot) => {
        const val = snapshot.val();
        const messages: ChatMessage[] = [];
        let unread = 0;

        if (val) {
          Object.entries(val).forEach(([msgId, m]: [string, any]) => {
            if (m) {
              const isDeletedForMe = m.deletedFor && m.deletedFor[userId];
              if (!isDeletedForMe) {
                messages.push({
                  id: msgId,
                  senderId: m.senderId,
                  senderName: m.senderName,
                  text: m.text,
                  timestamp: m.timestamp,
                  read: !!m.read,
                  isAudio: !!m.isAudio,
                  audioDuration: m.audioDuration,
                  edited: !!m.edited,
                  deletedFor: m.deletedFor || undefined,
                  deletedForEveryone: !!m.deletedForEveryone,
                  reactions: m.reactions || undefined,
                  replyTo: m.replyTo || undefined
                });

                if (m.senderId !== userId && !m.read) {
                  unread++;
                }
              }
            }
          });
        }

        // Sort messages
        messages.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

        conversationMap[chatId].messages = messages;
        conversationMap[chatId].lastMessage = messages[messages.length - 1];
        conversationMap[chatId].unreadCount = unread;

        updateStoreState();
      });

      unsubscribers.push(unsub);
    });

    // Handle empty partners case
    if (Object.keys(conversationMap).length === 0) {
      updateStoreState();
    }

    return () => {
      unsubscribers.forEach(unsub => unsub());
    };
  },

  markChatAsRead: async (chatId, userId) => {
    const chatRef = ref(db, `chats/${chatId}/messages`);
    const messages = getStore().conversations.find(c => c.chatId === chatId)?.messages || [];
    const updates: Record<string, any> = {};

    messages.forEach(m => {
      if (m.senderId !== userId && !m.read) {
        updates[`${m.id}/read`] = true;
      }
    });

    if (Object.keys(updates).length > 0) {
      await update(chatRef, updates);
    }
  }
}));

import { create } from 'zustand';

export interface AppNotification {
  id: string;
  title: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
  createdAt: string;
  read: boolean;
  metadata?: any;
}

export interface Toast {
  id: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
}

interface NotificationState {
  notifications: AppNotification[];
  toasts: Toast[];
  addToast: (message: string, type?: Toast['type']) => void;
  removeToast: (id: string) => void;
  addNotification: (title: string, message: string, type?: AppNotification['type'], metadata?: any) => void;
  fetchNotifications: (userId: string) => Promise<void>;
  markAsRead: (notificationId: string) => void;
  markAllAsRead: () => void;
  removeNotification: (notificationId: string) => void;
  removeAllNotifications: () => void;
}

export const useNotificationStore = create<NotificationState>((set) => ({
  notifications: [],
  toasts: [],
  addToast: (message, type = 'info') => {
    const id = `toast-${Date.now()}-${Math.random()}`;
    set((state) => ({
      toasts: [...state.toasts, { id, message, type }]
    }));
    setTimeout(() => {
      set((state) => ({
        toasts: state.toasts.filter((t) => t.id !== id)
      }));
    }, 4000);
  },
  removeToast: (id) => set((state) => ({
    toasts: state.toasts.filter((t) => t.id !== id)
  })),
  addNotification: (title, message, type = 'info', metadata) => {
    const newNotif: AppNotification = {
      id: `n-${Date.now()}-${Math.random()}`,
      title,
      message,
      type,
      createdAt: new Date().toISOString(),
      read: false,
      metadata
    };
    set((state) => ({
      notifications: [newNotif, ...state.notifications]
    }));
  },
  fetchNotifications: async (_userId) => {
    // Start empty to show only real notifications generated during session use
    set({ notifications: [] });
  },
  markAsRead: (notificationId) => set((state) => ({
    notifications: state.notifications.map((n) =>
      n.id === notificationId ? { ...n, read: true } : n
    )
  })),
  markAllAsRead: () => set((state) => ({
    notifications: state.notifications.map((n) => ({ ...n, read: true }))
  })),
  removeNotification: (notificationId) => set((state) => ({
    notifications: state.notifications.filter((n) => n.id !== notificationId)
  })),
  removeAllNotifications: () => set({ notifications: [] })
}));

